package Javabasicdemo;
// 2 types of constructors-1. Default Constructor-without parameter and without call function call in sub class
public class Constructor_default {
	int num;
	Constructor_default()
	{
		num=100;
		System.out.println(num);
	}
	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Constructor_default v=new Constructor_default();
	
	}

}
